164	/// One proof-tree line as captured (my own observation model, in JSON).
165	#[derive(Deserialize)]
166	struct LineRec {
167	    kind: String,
168	    depth: usize,
169	    status: String,
170	    #[serde(default)]
171	    by: bool,
172	    #[serde(default)]
173	    method_html: String,
174	    #[serde(default)]
175	    annotation: String,
176	    #[serde(default)]
177	    name: String,
178	    #[serde(default)]
179	    path: Vec<String>,
180	}
181	
182	/// A lemma's observed proof: the header status and its proof-tree lines.
183	#[derive(Deserialize)]
184	struct LemmaProof {
185	    lemma: String,
186	    decl_status: String,
187	    lines: Vec<LineRec>,
188	}
189	
190	/// Turn the observed line records into `ProofLine` values, building each step's
191	/// href with the crate's own URL builder so URL construction is under test too.
192	fn to_proof_lines<'a>(lp: &'a LemmaProof, idx: u64) -> Vec<ProofLine<'a>> {
193	    lp.lines
194	        .iter()
195	        .map(|r| match r.kind.as_str() {
196	            "step" => {
197	                let segs: Vec<&str> = r.path.iter().map(String::as_str).collect();
198	                ProofLine::Step {
199	                    depth: r.depth,
200	                    status: &r.status,
201	                    href: main_proof_path(idx, &lp.lemma, &segs),
202	                    method_html: &r.method_html,
203	                    annotation: &r.annotation,
204	                    by: r.by,
205	                }
206	            }
207	            "case" => ProofLine::Case { depth: r.depth, status: &r.status, name: &r.name },
208	            "next" => ProofLine::Next { depth: r.depth, status: &r.status },
209	            "qed" => ProofLine::Qed { depth: r.depth, status: &r.status },
210	            other => panic!("unknown proof-line kind {other:?}"),
211	        })
212	        .collect()
213	}
